/* ------------------------------------------------------------------ */
/*  Transform to canonical schema                                     */
/* ------------------------------------------------------------------ */

function toCanonical(r) {
  return {
    event_id: randomUUID(),
    canonical_name: r.name,
    aliases: [],
    start_date: r.start,
    end_date: r.end,
    date_uncertainty: r.uncertainty || "approximate",
    latitude: r.lat,
    longitude: r.lng,
    location_precision: r.precision || "region",
    conflict_type: r.type,
    parties: r.parties,
    casualties_low: r.casualties_low,
    casualties_high: r.casualties_high,
    casualty_basis: "scholarly_estimate",
    religion_tags: (r.tags || []).includes("religious") ? ["multiple"] : [],
    summary: r.summary,
    tags: r.tags || [],
    source_dataset: "manual",
    source_refs: [],
    confidence: r.uncertainty === "exact" ? 0.95 : r.uncertainty === "approximate" ? 0.7 : 0.4,
  };
}

const events = raw.map(toCanonical);

/* ------------------------------------------------------------------ */
/*  Write output                                                      */
/* ------------------------------------------------------------------ */

mkdirSync("public/data", { recursive: true });
writeFileSync("public/data/conflicts.json", JSON.stringify(events, null, 2));

console.log(`✓ Built ${events.length} conflict events → public/data/conflicts.json`);

// Print era distribution
const eras = { "Antiquity (-3000 to -500)": 0, "Classical (-500 to 500)": 0, "Medieval (500-1500)": 0, "Early Modern (1500-1800)": 0, "Industrial (1800-1914)": 0, "WWI era (1914-1918)": 0, "Interwar/WWII (1918-1945)": 0, "Cold War (1945-1991)": 0, "Post-Cold War (1991-2010)": 0, "Contemporary (2010+)": 0 };
events.forEach(e => {
  const y = e.start_date;
  if (y < -500) eras["Antiquity (-3000 to -500)"]++;
  else if (y < 500) eras["Classical (-500 to 500)"]++;
  else if (y < 1500) eras["Medieval (500-1500)"]++;
  else if (y < 1800) eras["Early Modern (1500-1800)"]++;
  else if (y < 1914) eras["Industrial (1800-1914)"]++;
  else if (y < 1919) eras["WWI era (1914-1918)"]++;
  else if (y < 1946) eras["Interwar/WWII (1918-1945)"]++;
  else if (y < 1991) eras["Cold War (1945-1991)"]++;
  else if (y < 2010) eras["Post-Cold War (1991-2010)"]++;
  else eras["Contemporary (2010+)"]++;
});
console.log("\nEra distribution:");
Object.entries(eras).forEach(([era, count]) => console.log(`  ${era}: ${count}`));
